import { useState } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function ProveedorForm({ proveedor, onClose }) {
  const [formData, setFormData] = useState({
    nombre: proveedor?.nombre || '',
    ruc: proveedor?.ruc || '',
    telefono: proveedor?.telefono || '',
    direccion: proveedor?.direccion || '',
    email: proveedor?.email || ''
  });
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (proveedor) {
        await api.put(`/proveedores/${proveedor.id}`, formData);
        toast.success('Proveedor actualizado');
      } else {
        await api.post('/proveedores', formData);
        toast.success('Proveedor creado');
      }
      onClose();
    } catch (error) {
      toast.error('Error al guardar');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
      <div className="bg-white p-6 rounded shadow-lg w-full max-w-md">
        <h2 className="text-xl font-bold mb-4">{proveedor ? 'Editar Proveedor' : 'Nuevo Proveedor'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="block text-sm">Nombre *</label>
            <input name="nombre" value={formData.nombre} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">RUC</label>
            <input name="ruc" value={formData.ruc} onChange={handleChange} className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">Teléfono</label>
            <input name="telefono" value={formData.telefono} onChange={handleChange} className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">Dirección</label>
            <input name="direccion" value={formData.direccion} onChange={handleChange} className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">Email</label>
            <input type="email" name="email" value={formData.email} onChange={handleChange} className="w-full border p-2 rounded" />
          </div>
          <div className="flex justify-end space-x-2">
            <button type="button" onClick={onClose} className="bg-gray-400 text-white px-4 py-2 rounded">Cancelar</button>
            <button type="submit" disabled={loading} className="bg-blue-600 text-white px-4 py-2 rounded">Guardar</button>
          </div>
        </form>
      </div>
    </div>
  );
}
